import functions_framework
import hashlib
import hmac
import json
import os
import time
from typing import Dict, Any, Tuple

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', '')
MAX_TIMESTAMP_DIFF = 300

def verify_signature(payload: bytes, signature: str, secret: str) -> bool:
    if not secret or not signature:
        return False
    
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def verify_timestamp(timestamp: int) -> bool:
    current_time = int(time.time())
    time_diff = abs(current_time - timestamp)
    return time_diff <= MAX_TIMESTAMP_DIFF

def validate_payment_event(event_data: Dict[str, Any]) -> Tuple[bool, str]:
    required_fields = ['event_type', 'transaction_id', 'amount', 'currency', 'status']
    
    for field in required_fields:
        if field not in event_data:
            return False, f"Missing required field: {field}"
    
    if not isinstance(event_data.get('amount'), (int, float)) or event_data['amount'] <= 0:
        return False, "Invalid amount"
    
    valid_currencies = ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD']
    if event_data.get('currency') not in valid_currencies:
        return False, "Invalid currency"
    
    valid_statuses = ['pending', 'completed', 'failed', 'refunded']
    if event_data.get('status') not in valid_statuses:
        return False, "Invalid status"
    
    valid_event_types = ['payment.created', 'payment.completed', 'payment.failed', 'payment.refunded']
    if event_data.get('event_type') not in valid_event_types:
        return False, "Invalid event type"
    
    transaction_id = str(event_data.get('transaction_id', ''))
    if not transaction_id or len(transaction_id) < 10 or len(transaction_id) > 100:
        return False, "Invalid transaction ID"
    
    return True, ""

def process_payment_event(event_data: Dict[str, Any]) -> Dict[str, Any]:
    event_type = event_data['event_type']
    transaction_id = event_data['transaction_id']
    amount = event_data['amount']
    currency = event_data['currency']
    status = event_data['status']
    
    print(f"Processing {event_type} for transaction {transaction_id}: {amount} {currency} - {status}")
    
    result = {
        'transaction_id': transaction_id,
        'processed': True,
        'timestamp': int(time.time())
    }
    
    return result

@functions_framework.http
def webhook_handler(request):
    if request.method != 'POST':
        return {'error': 'Method not allowed'}, 405
    
    content_type = request.headers.get('Content-Type', '')
    if 'application/json' not in content_type:
        return {'error': 'Content-Type must be application/json'}, 400
    
    signature = request.headers.get('X-Webhook-Signature', '')
    timestamp_header = request.headers.get('X-Webhook-Timestamp', '')
    
    if not signature:
        return {'error': 'Missing signature'}, 401
    
    if not timestamp_header:
        return {'error': 'Missing timestamp'}, 401
    
    try:
        timestamp = int(timestamp_header)
    except ValueError:
        return {'error': 'Invalid timestamp format'}, 400
    
    if not verify_timestamp(timestamp):
        return {'error': 'Request timestamp too old or invalid'}, 401
    
    try:
        payload = request.get_data()
        
        if len(payload) > 1048576:
            return {'error': 'Payload too large'}, 413
        
    except Exception as e:
        return {'error': 'Failed to read request body'}, 400
    
    if not verify_signature(payload, signature, WEBHOOK_SECRET):
        return {'error': 'Invalid signature'}, 401
    
    try:
        event_data = json.loads(payload)
    except json.JSONDecodeError:
        return {'error': 'Invalid JSON'}, 400
    
    if not isinstance(event_data, dict):
        return {'error': 'Invalid event data format'}, 400
    
    is_valid, error_message = validate_payment_event(event_data)
    if not is_valid:
        return {'error': f'Validation failed: {error_message}'}, 400
    
    try:
        result = process_payment_event(event_data)
        return {'success': True, 'result': result}, 200
    except Exception as e:
        print(f"Error processing event: {str(e)}")
        return {'error': 'Internal processing error'}, 500